import 'package:flutter/material.dart';
import '../services/api_service.dart';
import '../widgets/lms_shell.dart';
import '../widgets/lms_states.dart';

class NotificationsScreen extends StatefulWidget{const NotificationsScreen({super.key});@override State<NotificationsScreen> createState()=>_State();}
class _State extends State<NotificationsScreen>{final api=ApiService();bool loading=true;String? error;List<Map<String,dynamic>> items=[];int unread=0;@override void initState(){super.initState();load();}Future<void> load()async{setState(()=>loading=true);try{final d=await api.getNotifications();items=List<Map<String,dynamic>>.from(d['notifications']??const[]);unread=(d['unread_count'] as num?)?.toInt()??0;error=null;}catch(e){error=e.toString();}if(mounted)setState(()=>loading=false);}IconData icon(String type)=>type.contains('badge')?Icons.emoji_events:type.contains('nudge')||type.contains('reminder')?Icons.notifications_active:type=='at_risk'?Icons.warning_amber:Icons.notifications;@override Widget build(BuildContext context)=>LmsShell(title:'Notifications${unread>0?' ($unread)':''}',rootPage:true,actions:[TextButton(onPressed:unread==0?null:()async{await api.markNotificationRead(all:true);load();},child:const Text('Mark all read')),IconButton(tooltip:'Refresh notifications',onPressed:load,icon:const Icon(Icons.refresh))],body:loading?const LmsLoadingState(label:'Loading notifications'):error!=null?LmsErrorState(message:'We could not load your notifications.',onRetry:load):items.isEmpty?const LmsEmptyState(icon:Icons.notifications_none,title:'You’re all caught up',message:'Course, quiz, task, and booster updates will appear here.'):ListView.builder(padding:const EdgeInsets.all(20),itemCount:items.length,itemBuilder:(c,i){final n=items[i],read=n['is_read']==true||n['is_read']==1;return Card(color:read?null:Theme.of(c).colorScheme.primaryContainer,child:ListTile(leading:CircleAvatar(child:Icon(icon(n['type']?.toString()??''))),title:Text(n['title']?.toString()??'',style:TextStyle(fontWeight:read?FontWeight.normal:FontWeight.bold)),subtitle:Text('${n['message']??''}\n${n['scheduled_at']??n['created_at']??''}'),isThreeLine:true,onTap:read?null:()async{await api.markNotificationRead(id:n['id'] as int);load();}));}));}
